function PhoneMockup({
  src,
  alt,
  sizes,
  radius = 28,
}: {
  src: string;
  alt: string;
  sizes: string;
  radius?: number;
}) {
  return (
    <div
      style={{
        position: "relative",
        width: "100%",
        height: "100%",
        borderRadius: radius,
        border: "6px solid #18101f",
        overflow: "hidden",
        background: "#0a0612",
      }}
    >
      <img src={src} alt={alt} sizes={sizes} className="object-cover" />
      {/* Home indicator */}
      <div
        style={{
          position: "absolute",
          bottom: 8,
          left: "50%",
          transform: "translateX(-50%)",
          width: "36%",
          height: 3,
          borderRadius: 999,
          background: "rgba(255,255,255,0.28)",
          zIndex: 10,
        }}
      />
    </div>
  );
}

